{"source": "https://codeforces.com/problemset/problem/1056/F", "originalDifficulty": "interview", "concepts": ["Strings"], "hints": [], "starterCode": "", "referenceSolution": "from math import sqrt
class pro(object):
    def __init__(self,dif,sc):
        self.dif=dif
        self.sc=sc

    def __lt__(self,other):
        return self.dif>other.dif

T=int(input())
