    def mincostTickets(self, days: List[int], costs: List[int]) -> int:
        dp = [0] + [-1 for i in range(days[-1])]

        for day in days:
            dp[day] = 0

        for i in range(1, len(dp)):
            if dp[i] == -1:
                dp[i] = dp[i-1]

            else:
                dp[i] = min(
                    dp[i-1] + costs[0],
                    dp[max(i-7, 0)] + costs[1],
                    dp[max(i-30, 0)] + costs[2],
                )

