{"source": "https://leetcode.com/problems/shortest-subarray-to-be-removed-to-make-array-sorted/", "originalDifficulty": "interview", "concepts": ["Graphs"], "hints": [], "starterCode": "
class Solution:
    def findLengthOfShortestSubarray(self, arr: List[int]) -> int:
        ", "referenceSolution": "class Solution:
    def findLengthOfShortestSubarray(self, arr: List[int]) -> int:
        n = len(arr)
        if n<=1: 
            return 0
        l,r = n,-1

        for i in range(1,n):
            if arr[i]<arr[i-1]:
                l = i
                break
        # monotonicially increasing
        if l == n: return 0

        for j in range(n-2,-1,-1):
            if arr[j]>arr[j+1]:
                r = j
                break

        # you can delete all to the left of r (including r)
        # you can also delete all to the right of l (including l)
        ans = min(r+1,n-l)

        i = 0
        # sliding window, find the rightmost i for each j
        # note at all time i must be less than l
        for j in range(r+1,n):
            while i<l and arr[i] <= arr[j]:
                i += 1
            ans = min(ans,j-i)
        return ans", "fnName": "findLengthOfShortestSubarray"}

{"source": "https://leetcode.com/problems/maximum-product-subarray/", "originalDifficulty": "interview", "concepts": ["Sliding Window"], "hints": [], "starterCode": "
class Solution:
    def maxProduct(self, nums: List[int]) -> int:
        ", "referenceSolution": "class Solution:
     def maxProduct(self, nums):
         """
         :type nums: List[int]
         :rtype: int
         """
         def prod(nums):
             #function to calculate product
             prod = 1
             for i in nums:
                 prod*=i
             return prod
         def listsplit(ls1,index):
             result = []
             st = -1
             for i in index:
                 if i == 0:
                     st = i
                 else:
                     result.append(ls1[st+1:i])
                     st = i
             if st<len(ls1)-1:
                 result.append(ls1[st+1:])
             return result

         #main starts here
         if not nums:
             return 0
         if len(nums) == 1:
             return nums[0]
         #find zeros: if zeros are included the result would be zeros only
         result=[]
         if 0 in nums:
             zeros = [i for i in range(len(nums)) if nums[i] ==0]
             sublist = listsplit(nums,zeros)
             result.append(0)
         else:
             sublist = [nums]
         #find negative numbers. consider even or odd
         sublist = [i for i in sublist if i]

         for i in sublist:
             if prod(i) <0:
                 #there is negative number in the list
                 negative = [j for j in range(len(i)) if i[j] < 0]
                 left,right = negative[0],negative[-1]
                 if len(i) == 1:
                     result_t = i[0]
                 elif left == 0 or right == len(i) -1:
                     result_t = max(prod(i[left+1:]),prod(i[:right]))
                 else:
                     left_p,right_p = prod(i[:left]),prod(i[right+1:])
                     if left_p <= right_p:
                         result_t = prod(i[left+1:])
                     else:
                         result_t = prod(i[:right])
             else:
                 result_t = prod(i)
             result.append(result_t)
 ", "fnName": "maxProduct"}

