     def trap(self, height):
         """
         :type height: List[int]
         :rtype: int
         """
         if not height:
             return 0
         result = 0
         left = 0
         right = len(height) - 1
         while left < right:
             if height[left] <= height[right]:
                 tmp = height[left]
                 left += 1
                 while left < right and height[left] <= tmp:
                     result += tmp - height[left]
                     left += 1
             else:
                 tmp = height[right]
                 right -= 1
                 while left < right and height[right] <= tmp:
                     result += tmp - height[right]
                     right -=1 
         return result
", "fnName": "trap"}

{"source": "https://leetcode.com/problems/max-dot-product-of-two-subsequences/", "originalDifficulty": "interview", "concepts": ["Strings"], "hints": [], "starterCode": "
class Solution:
    def maxDotProduct(self, nums1: List[int], nums2: List[int]) -> int:
        ", "referenceSolution": "class Solution:
    def maxDotProduct(self, nums1: List[int], nums2: List[int]) -> int:

        # DP(a=index of last, b=index of last) = max of:
        #   DP(a-1, b)
        #   DP(a-1, i) + nums1[a] * max_or_min(nums2[i+1:b+1])
        #   same for b

        INF = int(1e9)
        n, m = len(nums1), len(nums2)

        DP = [-INF] * (m + 1)
        NDP = [-INF] * (m + 1)

        for a in range(n):

            for b in range(m):

                el = nums1[a] * nums2[b]

                diag = DP[b]

                NDP[b + 1] = max(el, DP[b + 1], NDP[b], diag, diag + el)

            DP, NDP = NDP, DP

        return DP[-1]", "fnName": "maxDotProduct"}

