{"source": "https://leetcode.com/problems/check-if-a-string-contains-all-binary-codes-of-size-k/", "originalDifficulty": "interview", "concepts": ["Trees"], "hints": [], "starterCode": "
class Solution:
    def hasAllCodes(self, s: str, k: int) -> bool:
        ", "referenceSolution": "class Solution:
    def hasAllCodes(self, s: str, k: int) -> bool:
        if len(s) < 2 ** k + k - 1:
            return False # Cannot be a string, as this is the de brujin length
        target = 2 ** k
        seen = set()
        cur_len = 0
        for end in range(k, len(s) + 1):
            chunk = s[end - k: end]
            if chunk not in seen:
                cur_len += 1
                seen.add(chunk)
                if cur_len == target:
                    return True
        return False
", "fnName": "hasAllCodes"}

