    def minOperationsMaxProfit(self, customers: List[int], boardingCost: int, runningCost: int) -> int:
        ", "referenceSolution": "class Solution:
    def minOperationsMaxProfit(self, customers: List[int], boardingCost: int, runningCost: int) -> int:
        if runningCost >= 4 * boardingCost:
            return -1
        result = sum(customers) // 4
        if (sum(customers) % 4) * boardingCost > runningCost:
            result += 1
        for customer in customers:
            if customer <= 1:
                result += 1
            else:
                break
        return result
", "fnName": "minOperationsMaxProfit"}

{"source": "https://leetcode.com/problems/count-unhappy-friends/", "originalDifficulty": "interview", "concepts": ["Sorting"], "hints": [], "starterCode": "
class Solution:
    def unhappyFriends(self, n: int, preferences: List[List[int]], pairs: List[List[int]]) -> int:
        ", "referenceSolution": "class Solution:
    def preferences_to_scores(self, preferences):
        scores = {}
        for u, up in enumerate(preferences):
            for s, v in enumerate(up):
                scores[(u, v)] = s
        return scores

    def unhappy_friends(self, scores, a, b):
        ret = set()
        for ai, aa in enumerate(a):
            af = a[1 - ai]
            for bi, bb in enumerate(b):
                bf = b[1 - bi]
                if scores[(aa, bb)] < scores[(aa, af)] and scores[(bb, aa)] < scores[(bb, bf)]:
                    ret.add(aa)
                    ret.add(bb)
        return ret

    def unhappyFriends(self, n: int, preferences: List[List[int]], pairs: List[List[int]]) -> int:
        scores = self.preferences_to_scores(preferences)
        ret = set()
        for i, a in enumerate(pairs):
            for j in range(i):
                b = pairs[j]
                ret |= self.unhappy_friends(scores, a, b)
        return len(ret)
", "fnName": "unhappyFriends"}

{"source": "https://leetcode.com/problems/maximum-length-of-repeated-subarray/", "originalDifficulty": "interview", "concepts": ["Sliding Window"], "hints": [], "starterCode": "
class Solution:
    def findLength(self, A: List[int], B: List[int]) -> int:
        ", "referenceSolution": "class Solution:
     def findLength(self, A, B):
         def check(length):
             seen = {A[i:i+length]
                     for i in range(len(A) - length + 1)}
             return any(B[j:j+length] in seen
                        for j in range(len(B) - length + 1))

         A = ''.join(map(chr, A))
         B = ''.join(map(chr, B))
         lo, hi = 0, min(len(A), len(B)) + 1
         while lo < hi:
             mi = int((lo + hi) / 2)
             if check(mi):
                 lo = mi + 1
             else:
                 hi = mi
         return lo - 1

", "fnName": "findLength"}

{"source": "https://leetcode.com/problems/numbers-at-most-n-given-digit-set/", "originalDifficulty": "interview", "concepts": ["Arrays"], "hints": [], "starterCode": "
class Solution:
    def atMostNGivenDigitSet(self, digits: List[str], n: int) -> int:
        ", "referenceSolution": "class Solution:
    def atMostNGivenDigitSet(self, digits: List[str], n: int) -> int:

        count = 0
        length = 1
        n_str = str(n)
        while length < len(n_str):
            count+= len(digits)**length
            length+=1

        digits_sorted = sorted(digits)


        ## now length should equal to len(n), we compare the number with same length
        current_digit = 0
        while current_digit < length:
            for digit in digits_sorted:
                next_round = False
                if digit < n_str[current_digit]:
                    count+=len(digits)**(length-current_digit-1)
                elif digit > n_str[current_digit]:
                    return count
                else:
                    if current_digit == length-1:
                        return count+1
                    else: 
                        current_digit+=1
                        next_round = True
                        break
            if not next_round:
                return count

        return count

", "fnName": "atMostNGivenDigitSet"}

