{"source": "https://leetcode.com/problems/reduce-array-size-to-the-half/", "originalDifficulty": "interview", "concepts": ["Arrays"], "hints": [], "starterCode": "
class Solution:
    def minSetSize(self, arr: List[int]) -> int:
        ", "referenceSolution": "from heapq import *
from collections import Counter

class Solution:
    def minSetSize(self, arr: List[int]) -> int:

        counter = Counter(arr)
        size = len(arr)

        # unique elements (remove half of them)
        if len(counter) == size:
            return (size - 1) // 2 + 1

        max_heap = [(-freq, value) for value, freq in list(counter.items())]
        heapify(max_heap)

        removed = 0  # number of elements removed
        removed_size = 0  # size of the remvoved set

        while removed < size//2:
            count, value = heappop(max_heap)
            count = -count  # change the count back to +ve
            removed += count
            removed_size += 1

        return removed_size


", "fnName": "minSetSize"}

{"source": "https://leetcode.com/problems/partition-to-k-equal-sum-subsets/", "originalDifficulty": "interview", "concepts": ["Backtracking"], "hints": [], "starterCode": "
class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        ", "referenceSolution": "class Solution:
     def canPartitionKSubsets(self, nums, k):
         """
         :type nums: List[int]
         :type k: int
         :rtype: bool
         """
         target,rem=divmod(sum(nums),k)
         if rem or max(nums)>target: return False
         n=len(nums)
         seen=[0]*n
         nums.sort(reverse=True)

         def dfs(k,index,current_sum):
             if k==1:
                 return True

             if current_sum==target:
                 return dfs(k-1,0,0)
             for i in range(index,n):
                 if not seen[i] and current_sum+nums[i]<=target:
                     seen[i]=1
                     if dfs(k,i+1,current_sum+nums[i]):
                         return True
                     seen[i]=0
             return False

         return dfs(k,0,0)
", "fnName": "canPartitionKSubsets"}

{"source": "https://leetcode.com/problems/triples-with-bitwise-and-equal-to-zero/", "originalDifficulty": "interview", "concepts": ["Arrays"], "hints": [], "starterCode": "
class Solution:
    def countTriplets(self, A: List[int]) -> int:
        ", "referenceSolution": "class Solution:
    def countTriplets(self, A: List[int]) -> int:
        counters = [0] * (1 << 16)
        counters[0] = len(A)
        for num in A:
            mask = (~num) & ((1 << 16) - 1)
            sm = mask
            while sm != 0:
                counters[sm] += 1
                sm = (sm - 1) & mask

        return sum(counters[num1 & num2] for num1 in A for num2 in A)
", "fnName": "countTriplets"}

{"source": "https://leetcode.com/problems/maximum-sum-circular-subarray/", "originalDifficulty": "interview", "concepts": ["Sliding Window"], "hints": [], "starterCode": "
class Solution:
    def maxSubarraySumCircular(self, A: List[int]) -> int:
        ", "referenceSolution": "class Solution:
    def maxSubarraySumCircular(self, A: List[int]) -> int:
        N = len(A)
        if(N==0):
            return 0
        curr_max = A[0]
        global_max = A[0]
        curr_min = A[0]
        global_min = A[0]
        flag = 0 
        if(A[0]>=0):
            flag=1

        for i in range(1, N):
            if(A[i]>=0):
                flag=1
            if(curr_max >= 0):
                curr_max = curr_max + A[i]    
            else:
                curr_max = A[i]

            if(curr_min >= 0):
                curr_min = A[i]
            else:
                curr_min = curr_min + A[i] 

            if(curr_max > global_max):
                global_max = curr_max
            if(curr_min < global_min):
                global_min = curr_min
        if(flag==0):
            return max(A)
        return max(global_max, sum(A) - global_min)", "fnName": "maxSubarraySumCircular"}

