{"source": "https://leetcode.com/problems/longest-consecutive-sequence/", "originalDifficulty": "interview", "concepts": ["Sorting"], "hints": [], "starterCode": "
class Solution:
    def longestConsecutive(self, nums: List[int]) -> int:
        ", "referenceSolution": "class Solution:
     def longestConsecutive(self, nums):
         """
         :type nums: List[int]
         :rtype: int
         """
         longest_streak = 0
         num_set = set(nums)
         for num in num_set:
             if num - 1 not in num_set:
                 current_num = num
                 current_streak = 1

                 while current_num + 1 in num_set:
                     current_num += 1
                     current_streak += 1

                 longest_streak = max(longest_streak, current_streak)
         return longest_streak", "fnName": "longestConsecutive"}
